Change 1: Replace:
  def _clean(val: str) -> str:
          return val.strip('"').strip("'")
with:
  def _clean(val: str) -> str:
          return val.strip('"').strip("'")

      def _add_article(val: str) -> str:
          """Prepend 'the' for country names that normally take an article."""
          if val.lower().startswith("united "):
              return "the " + val if not val.lower().startswith("the ") else val
          return val
